/**
 * Voxel Helicopter Simulator - Consolidated Build
 * Optimized with Tuning HUD & Persistence.
 */

// --- CONFIG & PERSISTENCE ---

const DEFAULT_CONFIG = {
  turnSpeed: 0.001,
  rollIntensity: 3,
  pitchIntensity: 8,
  accel: 0.75,
  mapScale: 100,
  startHeight: 100
};

let config = { ...DEFAULT_CONFIG };

function loadConfig() {
  const saved = localStorage.getItem('voxel_heli_config');
  if (saved) {
    try {
      config = { ...DEFAULT_CONFIG, ...JSON.parse(saved) };
      console.log("Config loaded from storage.");
    } catch (e) {
      console.error("Failed to parse saved config.");
    }
  }
}

function saveConfig() {
  localStorage.setItem('voxel_heli_config', JSON.stringify(config));
}

function resetConfig() {
  config = { ...DEFAULT_CONFIG };
  saveConfig();
  syncSlidersWithConfig();
}

// UI Toggles
let isConfigOpen = false;

function toggleConfig() {
  isConfigOpen = !isConfigOpen;
  const modal = document.getElementById('config-modal');
  if (modal) {
    modal.style.display = isConfigOpen ? 'flex' : 'none';
  }
  if (!isConfigOpen) {
    saveConfig(); // Save on close
  }
}

// --- CLASSES ---

class VoxelMap {
  constructor() {
    this.width = 1024;
    this.height = 1024;
    this.heightData = null;
    this.colorData = null;
    this.isLoaded = false;
  }

  init(colorImg, depthImg) {
    try {
      if (!colorImg || !depthImg) throw new Error("Images not loaded");
      colorImg.loadPixels();
      depthImg.loadPixels();

      this.heightData = new Uint8Array(this.width * this.height);
      for (let i = 0; i < this.width * this.height; i++) {
        this.heightData[i] = depthImg.pixels[i * 4];
      }

      this.colorData = new Uint32Array(this.width * this.height);
      for (let i = 0; i < this.width * this.height; i++) {
        const r = colorImg.pixels[i * 4];
        const g = colorImg.pixels[i * 4 + 1];
        const b = colorImg.pixels[i * 4 + 2];
        this.colorData[i] = (r << 16) | (g << 8) | b;
      }
      this.isLoaded = true;
      console.log("Map initialized.");
    } catch (e) {
      console.error("Map initialization failed:", e);
      document.getElementById('error-log').innerText = "Map Error: " + e.message;
    }
  }

  getHeight(x, y) {
    const ix = (Math.floor(x) % this.width + this.width) % this.width;
    const iy = (Math.floor(y) % this.height + this.height) % this.height;
    return this.heightData[iy * this.width + ix];
  }

  getColor(x, y) {
    const ix = (Math.floor(x) % this.width + this.width) % this.width;
    const iy = (Math.floor(y) % this.height + this.height) % this.height;
    return this.colorData[iy * this.width + ix];
  }
}

/**
 * The Camera class handles the "Physics" of the helicopter.
 * It manages position, orientation, and the forces (inertia) that make it feel like a flight sim.
 */
class Camera {
  constructor() {
    // Basic 3D Position
    this.x = 800;
    this.y = 800;
    this.height = config.startHeight; // Initial altitude from config
    
    // Orientation
    this.angle = 0;    // Yaw: Which way are we facing? (in Radians)
    this.horizon = 120;// Pitch: The vertical center of the view. 
                       // Moving this simulates the helicopter nose tilting up or down.
    this.roll = 0;     // Banking: The sideways tilt when turning.

    // Physics Engine (Velocity & Inertia)
    // Instead of moving the camera directly, we apply "force" to these velocities.
    this.velocity = { x: 0, y: 0, h: 0, a: 0 };
    
    // Friction: Every frame, we multiply velocity by 0.94.
    // This means we lose 6% of our speed per frame, causing the heli to "slide"
    // to a stop gradually rather than stopping instantly like a character in a platformer.
    this.friction = 0.94;

    // Smoothing Targets
    // We don't want the camera to "snap" to a tilt. We set a "target" and 
    // use math to smoothly slide toward it (Interpolation).
    this.targetHorizon = 120;
    this.targetRoll = 0;
  }

  /**
   * update() is called 60 times per second. 
   * It moves the camera based on current velocity and calculates the smooth tilting.
   */
  update() {
    // 1. Position Update: Add our current speed to our current position.
    this.x += this.velocity.x;
    this.y += this.velocity.y;
    this.height += this.velocity.h;
    this.angle += this.velocity.a;
    
    // 2. Safety Check: Don't let the helicopter go below the ground.
    if (this.height < 5) this.height = 5;
    
    // 3. Apply Friction: Slow down slightly every frame.
    this.velocity.x *= this.friction;
    this.velocity.y *= this.friction;
    this.velocity.h *= this.friction;
    this.velocity.a *= this.friction;
    
    // 4. Smooth Tilting (LERP):
    // "lerp" stands for Linear Interpolation. 
    // It means: "Move 10% of the way from my current tilt to the target tilt."
    // This creates the soft, organic movement as the helicopter responds to your keys.
    this.horizon = lerp(this.horizon, this.targetHorizon, 0.1);
    this.roll = lerp(this.roll, this.targetRoll, 0.1);
    
    // 5. Reset Targets: 
    // Every frame we want to "level out" unless the player is holding a key.
    this.targetHorizon = 120;
    this.targetRoll = 0;
  }

  /**
   * moveForward(amount)
   * Calculates movement based on the direction we are currently facing.
   */
  moveForward(amount) {
    const accel = config.accel;
    const pitchStr = config.pitchIntensity;
    const dt = deltaTime / 16.66; // Normalize to 60fps
    
    // Trigonometry 101: 
    // To move in the direction of an angle, we use Cosine for X and Sine for Y.
    // Imagine a circle: Cosine gets the horizontal "push", Sine gets the vertical "push".
    this.velocity.x += Math.cos(this.angle) * amount * accel * dt;
    this.velocity.y += Math.sin(this.angle) * amount * accel * dt;

    // Pitching: If we are moving forward/backward, we change the target horizon.
    // "Looking down" at the ground while speeding forward makes it feel like the nose is diving.
    this.targetHorizon = 120 - (amount * pitchStr);
  }

  /**
   * turn(amount)
   * Rotates the camera and calculates the banking effect.
   */
  turn(amount) {
    const turnSpd = config.turnSpeed;
    const rollStr = config.rollIntensity;
    const dt = deltaTime / 16.66;
    
    // Change the angular velocity (turning speed)
    this.velocity.a += amount * turnSpd * dt;

    // Banking (Roll): 
    // When a helicopter turns, it tilts sideways into the turn.
    // We set the target roll based on how hard we are turning.
    this.targetRoll = -amount * rollStr;
  }

  changeHeight(amount) {
    // Lift: Simple up/down velocity.
    const dt = deltaTime / 16.66;
    this.velocity.h += amount * 0.06 * dt;
  }
}

class Renderer {
  constructor(sw, sh) {
    this.width = sw;
    this.height = sh;
    this.buffer = createGraphics(this.width, this.height);
    this.buffer.pixelDensity(1);
    this.viewDistance = 600;
    this.scaleHeight = 120;
  }

  render(camera, map) {
    if (!map.isLoaded) return;
    this.buffer.loadPixels();
    const pixels = this.buffer.pixels;
    
    // Sky
    for (let i = 0; i < pixels.length; i += 4) {
      pixels[i] = 20; pixels[i+1] = 40; pixels[i+2] = 80; pixels[i+3] = 255;
    }
    
    const yBuffer = new Int32Array(this.width).fill(this.height);
    const cosP = Math.cos(camera.angle);
    const sinP = Math.sin(camera.angle);
    
    let dz = 1.0;
    for (let z = 1; z < this.viewDistance; z += dz) {
      dz += 0.005;
      const pLeftX = (cosP + sinP) * z;
      const pLeftY = (sinP - cosP) * z;
      const pRightX = (cosP - sinP) * z;
      const pRightY = (sinP + cosP) * z;
      const dx = (pRightX - pLeftX) / this.width;
      const dy = (pRightY - pLeftY) / this.width;
      
      let mapX = camera.x + pLeftX;
      let mapY = camera.y + pLeftY;
      
      for (let x = 0; x < this.width; x++) {
        // Sample the map height at this location
        const heightSample = map.getHeight(mapX, mapY);

        // Apply Roll: We tilt the horizon based on the camera's roll and 
        // the horizontal distance from the screen center.
        const rollOffset = (x - this.width / 2) * camera.roll * 0.01;
        const horizon = camera.horizon + rollOffset;
        
        /**
         * THE CORE PROJECTON FORMULA:
         * To turn a 3D coordinate into a 2D screen coordinate (Y), we use:
         * screenY = (CameraHeight - GroundHeight) / Distance * Scale + ScreenVerticalCenter
         * 
         * 1. (CameraHeight - GroundHeight): Gets the relative altitude.
         * 2. / z: "Perspective Division". Objects further away (larger z) become smaller/center-focused.
         * 3. * this.scaleHeight: A constant that makes the mountains look tall or flat.
         * 4. + horizon: Shifts the whole world up/down (Pitching).
         */
        let screenY = ((camera.height - heightSample) / z * config.mapScale + horizon) | 0;
        
        // Clamp to screen bounds
        if (screenY < 0) screenY = 0;
        if (screenY > this.height) screenY = this.height;
        
        // occlusion check: Only draw if this pixel is higher than what we've already drawn
        if (screenY < yBuffer[x]) {
          const color = map.getColor(mapX, mapY);
          const fog = Math.max(0, 1.0 - z / this.viewDistance);
          const r = ((color >> 16) & 0xFF) * fog;
          const g = ((color >> 8) & 0xFF) * fog;
          const b = (color & 0xFF) * fog;
          
          for (let y = screenY; y < yBuffer[x]; y++) {
            const idx = (y * this.width + x) * 4;
            pixels[idx] = r; pixels[idx+1] = g; pixels[idx+2] = b; pixels[idx+3] = 255;
          }
          yBuffer[x] = screenY;
        }
        mapX += dx; mapY += dy;
      }
    }
    this.buffer.updatePixels();
  }

  display() {
    image(this.buffer, 0, 0, width, height);
  }
}

// --- MAIN SKETCH ---

let voxelMap, camera, renderer, imgColor, imgDepth;

function preload() {
  imgColor = loadImage('data:image/png;base64,');
  imgDepth = loadImage('data:image/png;base64,');
}

function setup() {
  createCanvas(windowWidth, windowHeight);
  
  loadConfig();
  syncSlidersWithConfig();
  setupUIListeners();
  
  voxelMap = new VoxelMap();
  voxelMap.init(imgColor, imgDepth);
  camera = new Camera();
  renderer = new Renderer(400, 240);
  noSmooth();
  document.getElementById('status').innerText = "STATUS: RUNNING";
}

function draw() {
  background(0);
  
  // Only update handleInput and camera if config isn't open
  if (!isConfigOpen) {
    handleInput();
    camera.update();
  }
  
  if (voxelMap.isLoaded) {
    const th = voxelMap.getHeight(camera.x, camera.y);
    if (camera.height < th + 15) camera.height = th + 15;
  }
  
  renderer.render(camera, voxelMap);
  renderer.display();
  updateHUD();
}

function handleInput() {
  if (keyIsDown(87) || keyIsDown(UP_ARROW)) camera.moveForward(1);
  else if (keyIsDown(83) || keyIsDown(DOWN_ARROW)) camera.moveForward(-1);
  if (keyIsDown(65) || keyIsDown(LEFT_ARROW)) camera.turn(-1);
  else if (keyIsDown(68) || keyIsDown(RIGHT_ARROW)) camera.turn(1);
  if (keyIsDown(32)) camera.changeHeight(1);
  else if (keyIsDown(16)) camera.changeHeight(-1);
}

// --- UI HELPERS ---

function setupUIListeners() {
  const sliders = ['turn', 'roll', 'pitch', 'accel', 'map', 'start-h'];
  sliders.forEach(id => {
    const el = document.getElementById('s-' + id);
    if (el) {
      el.addEventListener('input', () => updateConfigFromSliders());
    }
  });
}

function updateConfigFromSliders() {
  config.turnSpeed = parseFloat(document.getElementById('s-turn').value);
  config.rollIntensity = parseFloat(document.getElementById('s-roll').value);
  config.pitchIntensity = parseFloat(document.getElementById('s-pitch').value);
  config.accel = parseFloat(document.getElementById('s-accel').value);
  config.mapScale = parseFloat(document.getElementById('s-map').value);
  config.startHeight = parseFloat(document.getElementById('s-start-h').value);
  
  // Real-time updates
  camera.height = config.startHeight;
  
  // Update view labels
  document.getElementById('v-turn').innerText = config.turnSpeed;
  document.getElementById('v-roll').innerText = config.rollIntensity;
  document.getElementById('v-pitch').innerText = config.pitchIntensity;
  document.getElementById('v-accel').innerText = config.accel;
  document.getElementById('v-map').innerText = config.mapScale;
  document.getElementById('v-start-h').innerText = config.startHeight;
}

function syncSlidersWithConfig() {
  document.getElementById('s-turn').value = config.turnSpeed;
  document.getElementById('s-roll').value = config.rollIntensity;
  document.getElementById('s-pitch').value = config.pitchIntensity;
  document.getElementById('s-accel').value = config.accel;
  document.getElementById('s-map').value = config.mapScale;
  document.getElementById('s-start-h').value = config.startHeight;
  
  document.getElementById('v-turn').innerText = config.turnSpeed;
  document.getElementById('v-roll').innerText = config.rollIntensity;
  document.getElementById('v-pitch').innerText = config.pitchIntensity;
  document.getElementById('v-accel').innerText = config.accel;
  document.getElementById('v-map').innerText = config.mapScale;
  document.getElementById('v-start-h').innerText = config.startHeight;
}

function updateHUD() {
  const fpsEl = document.getElementById('fps');
  const posEl = document.getElementById('pos');
  if (fpsEl) fpsEl.innerText = `FPS: ${Math.round(frameRate())}`;
  if (posEl) posEl.innerText = `POS: X:${Math.round(camera.x)} Y:${Math.round(camera.y)} H:${Math.round(camera.height)}`;
}

function windowResized() {
  resizeCanvas(windowWidth, windowHeight);
}
